<?php
namespace App\Services\Notifications;
use App\Models\Notifications\AppNotification; use App\Models\Notifications\NotificationDeliveryLog; use App\Models\User; use App\Models\UserPushToken; use App\Services\Firebase\FcmService as FirebaseFcmService;
class FcmService { public function __construct(private FirebaseFcmService $firebase){} public function sendToToken(string $token,string $title,string $body,array $data,?AppNotification $notification=null):array{ $log=null; if($notification){$log=NotificationDeliveryLog::create(['notification_id'=>$notification->id,'user_id'=>$notification->user_id,'channel'=>'push','provider'=>'fcm','status'=>'pending','request_payload'=>['token'=>$token,'title'=>$title,'body'=>$body,'data'=>$data],'attempted_at'=>now()]);} $result=$this->firebase->sendToDevice($token,$title,$body,$data,null,1,['user_id'=>$notification?->user_id,'notification_type'=>$data['type']??null]); if(!$result['success'] && str_contains(strtolower((string)$result['error']),'invalid')){$this->deactivateInvalidToken($token);} if($log){$log->update(['status'=>$result['success']?'sent':'failed','response_payload'=>$result,'error_message'=>$result['error']??null,'delivered_at'=>$result['success']?now():null]);} return $result;} public function sendToUser(User $user,string $title,string $body,array $data,?AppNotification $notification=null):array{ $results=[]; foreach($user->pushTokens()->where('is_active',true)->get() as $t){$results[]=$this->sendToToken($t->token,$title,$body,$data,$notification);} return ['success'=>collect($results)->contains('success',true),'results'=>$results];} public function deactivateInvalidToken(string $token):void{UserPushToken::where('token',$token)->update(['is_active'=>false]);}}
